static void (*orig_viewDidAppear)(id,SEL,BOOL);
static void tp_viewDidAppear(UIViewController*self,SEL _cmd,BOOL animated){orig_viewDidAppear(self,_cmd,animated);dispatch_after(dispatch_time(DISPATCH_TIME_NOW,.35*NSEC_PER_SEC),dispatch_get_main_queue(),^{@try{[TPUIInjector.shared scanFrom:self];}@catch(NSException*x){}});}
static void TPConfigure(void){ UIViewController *top; for(UIWindow*w in UIApplication.sharedApplication.windows)if(w.isKeyWindow)top=w.rootViewController; while(top.presentedViewController)top=top.presentedViewController; UIAlertController*a=[UIAlertController alertControllerWithTitle:@"TranslatePlugin 设置" message:@"OpenAI-compatible API" preferredStyle:1]; NSArray *vals=@[TPSettings.shared.baseURL,TPSettings.shared.apiKey,TPSettings.shared.model,TPSettings.shared.targetLanguage]; NSArray *names=@[@"Base URL",@"API Key",@"Model",@"Target language"]; for(int i=0;i<4;i++)[a addTextFieldWithConfigurationHandler:^(UITextField*t){t.placeholder=names[i];t.text=vals[i];t.secureTextEntry=(i==1);}]; [a addAction:[UIAlertAction actionWithTitle:@"保存" style:0 handler:^(id x){TPSettings.shared.baseURL=a.textFields[0].text;[TPSettings.shared setAPIKey:a.textFields[1].text];TPSettings.shared.model=a.textFields[2].text;TPSettings.shared.targetLanguage=a.textFields[3].text;}]]; [a addAction:[UIAlertAction actionWithTitle:@"取消" style:1 handler:nil]]; [top presentViewController:a animated:YES completion:nil]; }
__attribute__((constructor)) static void init(){ @autoreleasepool { NSString*b=NSBundle.mainBundle.bundleIdentifier.lowercaseString;if(![b containsString:@"whatsapp"])return; Method m=class_getInstanceMethod(UIViewController.class,@selector(viewDidAppear:));orig_viewDidAppear=(void*)method_getImplementation(m);method_setImplementation(m,(IMP)tp_viewDidAppear); [[NSNotificationCenter defaultCenter] addObserverForName:UIApplicationDidBecomeActiveNotification object:nil queue:NSOperationQueue.mainQueue usingBlock:^(id n){ static dispatch_once_t once;dispatch_once(&once,^{if(!TPSettings.shared.apiKey.length)dispatch_after(dispatch_time(DISPATCH_TIME_NOW,2*NSEC_PER_SEC),dispatch_get_main_queue(),^{TPConfigure();});}); }]; } }
